class Solution {
public:
    vector<int> maximumCount(vector<int>& nums, vector<vector<int>>& queries) {
        vector<int> res;
        for (auto& query : queries) {
            int idx = query[0], val = query[1];
            nums[idx] = val;
            int prefix = 0, suffix = 0;
            for (int i = 0; i < idx; i++) {
                if (isPrime(nums[i])) prefix++;
            }
            for (int i = idx + 1; i < nums.size(); i++) {
                if (isPrime(nums[i])) suffix++;
            }
            res.push_back(max(prefix, suffix));
        }
        return res;
    }
    bool isPrime(int x) {
        if (x <= 1) return false;
        for (int i = 2; i * i <= x; i++) {
            if (x % i == 0) return false;
        }
        return true;
    }
};
